struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using operator<<
        stream << packet_id;

        // Write username using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count (as uint32_t in little endian) and then elements
        // Using operator<< which internally calls write_container
        stream << hexi::prefixed(scores);

        // Write metadata using null_terminated adaptor
