    // Create a buffer_adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer, hexi::init_empty_t{});

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the serialise method of the packet on the stream
    packet.serialise(stream);

    // Return the populated buffer
    return buffer;
}
```

