```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create a binary stream using the buffer adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    MessageHeader header;

    // Read the message_type using the stream extraction operator
    stream >> header.message_type;

    // Read the body_length using the stream extraction operator
    stream >> header.body_length;

    // Use the skip() function to skip the body data based on body_length
    stream.skip(header.body_length);

    // Read the footer using the stream extraction operator
    stream >> header.footer;

    return header;
}
