#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer_adaptor for the buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Calculate total size needed: header (4 bytes) + items (each item is 4 bytes)
    const size_t header_size = sizeof(header);
    const size_t items_size = items.size() * sizeof(uint32_t);
    const size_t total_size = header_size + items_size;

    // Check if buffer has enough free space
    if (adaptor.free() < total_size) {
        return false; // Insufficient space
    }

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Write header using operator<<
    stream << header;

    // Write items using write_container
    stream.write_container(items);

    return true; // Write successful
}
