#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance for demonstration
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate initial state: free list contains preallocated blocks
    // (The constructor calls initialise() which creates a linked list of free blocks)

    // Allocate a block - this will pop a block from the free list
    int* block1 = allocator.allocate(42);
    // Now the free list has one less block

    // Deallocate the block - this will push it back to the free list
    allocator.deallocate(block1);
    // Free list now has the block back

    // Allocate multiple blocks to show the FIFO nature
    int* blocks[5];
    for (int i = 0; i < 5; ++i) {
        blocks[i] = allocator.allocate(i);
        // Each allocation pops from the head of the free list
    }

    // Deallocate in reverse order to show LIFO behavior
    for (int i = 4; i >= 0; --i) {
        allocator.deallocate(blocks[i]);
        // Each deallocation pushes to the head of the free list
    }

    // Demonstrate fallback to system allocator when free list is exhausted
    int* system_blocks[element_count + 1];
    for (size_t i = 0; i <= element_count; ++i) {
        system_blocks[i] = allocator.allocate(i);
        // After exhausting preallocated blocks, system allocator is used
    }

    // Clean up allocated blocks
    for (size_t i = 0; i <= element_count; ++i) {
        allocator.deallocate(system_blocks[i]);
        // Excess blocks are deallocated via system delete
    }
}
```

