```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Handle edge case: empty input
    if (chunks.empty()) {
        return 0;
    }

    // Calculate total required size
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Handle edge case: zero-sized buffer
    if (total_size == 0) {
        return 0;
    }

    // Create buffer with sufficient capacity
    std::vector<uint8_t> buffer(total_size);

    // Create adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    std::size_t total_written = 0;

    // Write each chunk with size tracking
    for (const auto& chunk : chunks) {
        // Check available space before write
        if (adaptor.free() < chunk.size()) {
            // Handle insufficient space - write only what fits
            std::size_t write_size = std::min(adaptor.free(), chunk.size());
            adaptor.write(chunk.data(), write_size);
            total_written += write_size;
            break; // Stop writing if buffer is full
        } else {
            // Sufficient space - write entire chunk
            adaptor.write(chunk.data(), chunk.size());
            total_written += chunk.size();
        }
    }

    // Return the total size written
    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Handle edge case: invalid chunk_size
    if (chunk_size == 0) {
        return {};
    }

    // Create a copy of the buffer to work with (since adaptor requires non-const)
    std::vector<uint8_t> working_buffer = buffer;

    // Create adaptor for the buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(working_buffer);

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read (minimum of chunk_size and remaining data)
        std::size_t read_size = std::min(chunk_size, adaptor.size());

        // Create temporary buffer for reading
        std::vector<uint8_t> temp(read_size);

        // Perform read operation
        adaptor.read(temp.data(), read_size);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Check remaining data after read (as per specification)
        // This is automatically handled by the loop condition
    }

    return result;
}
```

