struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization
        adaptor.write(sensor_id);

        // Convert and write each temperature value
        for (const auto& temp : temperatures) {
            float temp_le = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(temp_le);
        }

        // Convert and write pressure value
        double pressure_le = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(pressure_le);
    }

    void serialise(auto& adaptor) {
        // Deserialization
        adaptor.read(sensor_id);

        // Read and convert each temperature value
        temperatures.resize(temperatures.size()); // Ensure vector has capacity
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure value
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and adaptor
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream and serialize
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    // Create adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Deserialize into new MeasurementData object
    MeasurementData result;
    stream.deserialise(result);

    return result;
}

